/**
 * Phase 7E — Per-build CSP nonce tests.
 *
 * The nonce is generated by `scripts/add-sri.mjs` and stamped into:
 *  - the `Content-Security-Policy` `script-src` directive in `build/_headers`
 *    (replacing the `__CSP_NONCE__` placeholder emitted by `static/_headers`)
 *  - the `nonce="…"` attribute on the no-flash inline `<script>` in
 *    `build/index.html` (the same nonce as the headers)
 *  - the canonical `build/csp-nonce.txt` file (one nonce per line, hex)
 *
 * These tests require `build/` to exist, which is the case after `pnpm build`.
 * The build is part of the pre-commit chain (`pnpm check && pnpm lint && pnpm test`),
 * so the directory is expected to be present. The tests fail loudly if it isn't
 * — that is intentional: a missing `build/` means the build was never run, and
 * any test that reads the bundle is invalid.
 *
 * The tests run in the `server` Vitest project (Node environment, no browser
 * globals) so that `node:fs` is available.
 */
import { describe, expect, it } from 'vitest';
import { readFile, stat } from 'node:fs/promises';
import { resolve } from 'node:path';

const repoRoot = resolve(__dirname, '..', '..');
const buildDir = resolve(repoRoot, 'build');
const headersPath = resolve(buildDir, '_headers');
const indexPath = resolve(buildDir, 'index.html');
const nonceFilePath = resolve(buildDir, 'csp-nonce.txt');

const NONCE_HEX = /^[0-9a-f]{32}$/;

async function ensureBuildExists() {
	try {
		await stat(buildDir);
	} catch {
		throw new Error(`build directory not found at ${buildDir} — run \`pnpm build\` first.`);
	}
}

async function readIfExists(path: string): Promise<string | null> {
	try {
		return await readFile(path, 'utf8');
	} catch {
		return null;
	}
}

describe('per-build CSP nonce', () => {
	it('build/_headers is produced by the build', async () => {
		await ensureBuildExists();
		const headers = await readIfExists(headersPath);
		expect(headers, 'build/_headers must exist after pnpm build').not.toBeNull();
	});

	it('build/csp-nonce.txt is produced by the build', async () => {
		await ensureBuildExists();
		const nonceFile = await readIfExists(nonceFilePath);
		expect(nonceFile, 'build/csp-nonce.txt must exist after pnpm build').not.toBeNull();
	});

	it('build/csp-nonce.txt contains a 32-char lowercase hex nonce', async () => {
		await ensureBuildExists();
		const nonceFile = await readIfExists(nonceFilePath);
		expect(nonceFile).not.toBeNull();
		const nonce = (nonceFile ?? '').trim();
		expect(nonce, 'csp-nonce.txt must be non-empty').not.toBe('');
		expect(nonce, 'nonce must be 32 lowercase hex chars (128-bit)').toMatch(NONCE_HEX);
	});

	it('build/_headers script-src contains a `nonce-` directive with the same hex value', async () => {
		await ensureBuildExists();
		const headers = await readIfExists(headersPath);
		const nonceFile = await readIfExists(nonceFilePath);
		expect(headers).not.toBeNull();
		expect(nonceFile).not.toBeNull();
		const nonce = (nonceFile ?? '').trim();

		// Extract the Content-Security-Policy line. The Netlify
		// `_headers` format uses a single tab between the path and the
		// directive, so the regex anchors on `[ \t]*` rather than `^`.
		const cspMatch = (headers ?? '').match(/^[ \t]*Content-Security-Policy:\s*(.+)$/m);
		expect(cspMatch, 'CSP directive must be present in build/_headers').not.toBeNull();
		const csp = cspMatch?.[1] ?? '';

		// Extract the script-src directive (the segment between `script-src`
		// and the next `;` or end-of-string).
		const scriptSrcMatch = csp.match(/script-src\s+([^;]+)/);
		expect(scriptSrcMatch, 'script-src must be present in CSP').not.toBeNull();
		const scriptSrc = scriptSrcMatch?.[1] ?? '';

		// The script-src must contain a `nonce-<hex>` token matching the
		// canonical nonce from csp-nonce.txt.
		const nonceMatch = scriptSrc.match(/'nonce-([0-9a-f]+)'/i);
		expect(nonceMatch, 'script-src must contain a `nonce-…` token').not.toBeNull();
		expect(nonceMatch?.[1], 'nonce hex must be 32 chars').toMatch(/^[0-9a-f]{32}$/i);
		expect(nonceMatch?.[1], 'nonce in CSP must match csp-nonce.txt').toBe(nonce);
	});

	it('the inline <script> in build/index.html carries the same nonce', async () => {
		await ensureBuildExists();
		const indexHtml = await readIfExists(indexPath);
		const nonceFile = await readIfExists(nonceFilePath);
		expect(indexHtml).not.toBeNull();
		expect(nonceFile).not.toBeNull();
		const nonce = (nonceFile ?? '').trim();

		// Find every <script …> opening tag. The no-flash theme bootstrap is
		// the first <script> in the file (SvelteKit's own inline module
		// bootstrap is in <body>, not <head>). We require at least one
		// stamped nonce attribute to exist; the scanner is the
		// add-sri.mjs contract.
		const scriptTags = (indexHtml ?? '').match(/<script\b[^>]*>/g) ?? [];
		expect(scriptTags.length, 'at least one <script> tag must exist in index.html').toBeGreaterThan(
			0
		);
		const stamped = scriptTags.filter((t) => new RegExp(`nonce="${nonce}"`).test(t));
		expect(
			stamped.length,
			`at least one <script> in build/index.html must carry nonce="${nonce}"`
		).toBeGreaterThan(0);
	});

	it('static/_headers uses the __CSP_NONCE__ placeholder (so add-sri.mjs can replace it)', async () => {
		// This guards the static → build contract: the source file in
		// `static/_headers` MUST contain the placeholder, otherwise the
		// `add-sri.mjs` script would not know what to replace. The
		// placeholder is removed in the build output, so this only
		// applies to the source.
		const staticHeadersPath = resolve(repoRoot, 'static', '_headers');
		const src = await readIfExists(staticHeadersPath);
		expect(src).not.toBeNull();
		expect(
			src ?? '',
			'static/_headers must contain the __CSP_NONCE__ placeholder in script-src'
		).toContain('__CSP_NONCE__');
	});
});
